'use client';

import * as React from 'react';
import Link from 'next/link';
import {
  SidebarProvider,
  Sidebar,
  SidebarHeader,
  SidebarContent,
  SidebarTrigger,
  SidebarMenu,
  SidebarMenuItem,
  SidebarMenuButton,
} from '@/components/ui/sidebar';
import {
  Users,
  FileCheck,
  FolderKanban,
  User,
  Bell,
} from 'lucide-react';
import { UserNav } from '@/components/user-nav';
import { usePathname } from 'next/navigation';
import type { User as UserType } from '@/lib/types';
import { Skeleton } from '@/components/ui/skeleton';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import Image from 'next/image';

export default function AppLayout({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const [user, setUser] = React.useState<UserType | null>(null);
  const [isLoading, setIsLoading] = React.useState(true);

  React.useEffect(() => {
    const storedUser = localStorage.getItem('proconecta_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setIsLoading(false);
  }, []);

  const isUserAdmin = user?.role === 'administrator';
  const isUserSolicitante = user?.role === 'solicitante';
  const isUserEstudiante = user?.role === 'estudiante';

  const renderAdminSidebar = () => {
    if (isLoading) {
      return (
        <div className="p-4 space-y-4">
          <Skeleton className="h-8 w-3/4" />
          <Skeleton className="h-8 w-full" />
          <Skeleton className="h-8 w-full" />
          <Skeleton className="h-8 w-full" />
        </div>
      );
    }
    return (
      <SidebarMenu className="p-4">
        <SidebarMenuItem>
          <SidebarMenuButton asChild isActive={pathname === '/administrador/usuarios'}>
            <Link href="/administrador/usuarios">
              <Users />
              Usuarios
            </Link>
          </SidebarMenuButton>
        </SidebarMenuItem>
        <SidebarMenuItem>
          <SidebarMenuButton asChild isActive={pathname === '/administrador/solicitudes'}>
            <Link href="/administrador/solicitudes">
              <FileCheck />
              Solicitudes
            </Link>
          </SidebarMenuButton>
        </SidebarMenuItem>
        <SidebarMenuItem>
          <SidebarMenuButton asChild isActive={pathname.startsWith('/estudiante/proyectos')}>
            <Link href="/estudiante/proyectos">
              <FolderKanban />
              Proyectos
            </Link>
          </SidebarMenuButton>
        </SidebarMenuItem>
        <SidebarMenuItem>
          <SidebarMenuButton asChild isActive={pathname === '/perfil'}>
            <Link href="/perfil">
              <User />
              Perfil
            </Link>
          </SidebarMenuButton>
        </SidebarMenuItem>
      </SidebarMenu>
    );
  };

  const renderStudentOrSolicitanteNav = () => (
    <header className="sticky top-0 z-50 w-full border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
      <div className="container flex h-16 items-center">
        <div className="mr-4 flex">
          <Link href="/dashboard" className="mr-6 flex items-center space-x-2">
            <Image src="/images/logo.png" alt="Logo" width={200} height={50} />
          </Link>
          <nav className="hidden items-center space-x-6 text-sm font-medium md:flex">
            {isUserSolicitante ? (
              <>
                <Link
                  href="/dashboard"
                  className={cn(
                    'transition-colors hover:text-foreground/80',
                    pathname === '/dashboard' ? 'text-foreground' : 'text-foreground/60'
                  )}
                >
                  Inicio
                </Link>
                <Link
                  href="/solicitante/solicitudes"
                  className={cn(
                    'transition-colors hover:text-foreground/80',
                    pathname.startsWith('/solicitante/solicitudes')
                      ? 'text-foreground'
                      : 'text-foreground/60'
                  )}
                >
                  Solicitudes
                </Link>
              </>
            ) : (
              <>
                <Link
                  href="/dashboard"
                  className={cn(
                    'transition-colors hover:text-foreground/80',
                    pathname === '/dashboard' ? 'text-foreground' : 'text-foreground/60'
                  )}
                >
                  Inicio
                </Link>
                <Link
                  href="/estudiante/proyectos"
                  className={cn(
                    'transition-colors hover:text-foreground/80',
                    pathname.startsWith('/estudiante/proyectos')
                      ? 'text-foreground'
                      : 'text-foreground/60'
                  )}
                >
                  Proyectos
                </Link>
              </>
            )}
            <a
              href="mailto:RafaelUribeC@outlook.com"
              className="transition-colors hover:text-foreground/80 text-foreground/60"
            >
              Contacto
            </a>
          </nav>
        </div>
        <div className="flex flex-1 items-center justify-between md:justify-end space-x-2">
          <div className="md:hidden">{/* Placeholder for mobile nav trigger if needed in future */}</div>
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="icon">
              <Bell className="h-5 w-5" />
            </Button>
            <UserNav />
          </div>
        </div>
      </div>
    </header>
  );

  const isDashboard = pathname === '/dashboard';

  if (isUserAdmin) {
    return (
      <SidebarProvider>
        <>
          {/* Barra superior fuera del flex para full width */}
          <header
            className="sticky top-0 z-10 flex h-16 items-center gap-4 border-b bg-background px-4 md:px-6"
            style={{ position: 'sticky', top: 0, left: 0, right: 0, width: '100vw' }}
          >
            <SidebarTrigger className="md:hidden" />
            <div className="flex-1"></div>
            <UserNav />
          </header>

          <div className="flex min-h-screen">
            <Sidebar>
              <SidebarContent>
                <SidebarHeader className="p-4">
                  <Link href="/administrador/solicitudes" className="flex items-center gap-2">
                    <Image src="/images/logo.png" alt="Logo" width={200} height={50} />
                  </Link>
                </SidebarHeader>
                {renderAdminSidebar()}
              </SidebarContent>
            </Sidebar>
            <div className="flex-1 flex flex-col">
              <main className="flex-grow p-4 md:p-6 overflow-auto">{children}</main>
            </div>
          </div>
        </>
      </SidebarProvider>
    );
  }

  return (
    <div>
      {renderStudentOrSolicitanteNav()}
      <main className={cn(!isDashboard && 'container py-6 md:py-10')}>{children}</main>
    </div>
  );
}
